def polish_policy(self, flow, state, context, tools):
    if not flow.slots['source'].check_if_filled():
        self.ambiguity.declare('specific', metadata={'missing_slot': flow.entity_slot})
        return DisplayFrame(flow.name())

    post_id, sec_id = self._resolve_source_ids(flow, state, tools)

    text, tool_log = self.llm_execute(flow, state, context, tools)
    parsed = self.engineer.apply_guardrails(text) or {}

    if parsed.get('fallback'):
        next_flow = parsed['fallback']
        self.flow_stack.fallback(next_flow)
        state.keep_going = True
        return DisplayFrame(flow.name(),
            thoughts=parsed.get('reason', ''),
            metadata={'fallback': next_flow})

    saved, _ = self.engineer.tool_succeeded(tool_log, 'revise_content')
    if not saved:
        return self.error_frame(flow, 'failed_to_save',
            thoughts='revise_content did not land.',
            code=text,
            failed_tool='revise_content')

    flow.status = 'Completed'
    frame = DisplayFrame(flow.name(),
        thoughts=parsed.get('summary', ''),
        metadata={
            'post_id': post_id,
            'sec_id': sec_id,
            'target_span': parsed.get('target'),
            'used_findings': parsed.get('used', []),
        })
    frame.add_block({'type': 'card', 'data': self._read_post_content(post_id, tools)})
    return frame

class PolishFlow(ReviseParentFlow):
  def __init__(self):
    super().__init__()
    self.flow_type = 'polish'
    self.dax = '{3BD}'
    self.goal = 'editing of a specific paragraph, sentence or phrase; improves word choice, tightens sentences, fixes transitions, and smooths flow without changing meaning or structure. The scope is within a single paragraph or image, not across the whole post'
    self.slots = {
      'source': SourceSlot(1, 'sec'),
      'style_notes': FreeTextSlot(priority='optional'),
      'image': ImageSlot(priority='optional'),
    }
    self.tools = ['read_metadata', 'read_section', 'write_text', 'revise_content']
